tests:
def test_no_false_negatives():
    bf = BloomFilter(size=256, num_hashes=4)
    items = ['apple', 'banana', 'cherry', 'date']
    for it in items:
        bf.add(it)
    for it in items:
        assert bf.contains(it) is True

def test_fill_ratio():
    bf = BloomFilter(size=128, num_hashes=3)
    assert bf.approximate_fill_ratio() == 0.0
    for i in range(20):
        bf.add(f'item{i}')
    assert 0.0 < bf.approximate_fill_ratio() <= 1.0

def test_counting_remove_missing():
    cbf = CountingBloomFilter(size=128, num_hashes=3)
    assert cbf.remove('never_added') is False
